import React, { useState, useEffect } from 'react';
import type { CoachStyle, ModelOption, Theme, UserPreferences } from '../types';

const DEFAULT_PREFS: UserPreferences = {
  coachStyle: 'coach',
  model: 'claude-sonnet-4-6',
  theme: 'auto',
  showStreakInPanel: false,
};

const COACH_STYLES: { id: CoachStyle; label: string; desc: string }[] = [
  { id: 'coach', label: 'Coach', desc: 'Warm and encouraging.' },
  { id: 'professor', label: 'Professor', desc: 'Precise and formal.' },
  { id: 'peer', label: 'Peer', desc: 'Casual and friendly.' },
];

const MODELS: { id: ModelOption; label: string; cost: string }[] = [
  { id: 'claude-sonnet-4-6', label: 'Sonnet 4.6', cost: '~$0.005 / hint' },
  { id: 'claude-haiku-4-5-20251001', label: 'Haiku 4.5', cost: '~$0.001 / hint' },
  { id: 'claude-opus-4-6', label: 'Opus 4.6', cost: '~$0.03 / hint' },
];

export function SettingsApp() {
  const [apiKey, setApiKey] = useState('');
  const [prefs, setPrefs] = useState<UserPreferences>(DEFAULT_PREFS);
  const [keyStatus, setKeyStatus] = useState<'idle' | 'testing' | 'ok' | 'fail'>('idle');
  const [lastTested, setLastTested] = useState<string | null>(null);
  const [resetConfirm, setResetConfirm] = useState(false);
  const [saved, setSaved] = useState(false);

  function applyTheme(theme: string) {
    if (theme === 'dark' || (theme === 'auto' && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }

  useEffect(() => {
    chrome.storage.local.get(['apiKey', 'preferences', 'lastKeyTest']).then((res) => {
      if (res.apiKey) setApiKey(res.apiKey as string);
      if (res.preferences) {
        const p = res.preferences as UserPreferences;
        setPrefs(p);
        applyTheme(p.theme);
      } else {
        applyTheme('auto');
      }
      if (res.lastKeyTest) setLastTested(res.lastKeyTest as string);
    });
  }, []);

  async function testKey() {
    setKeyStatus('testing');
    try {
      const { ok } = await chrome.runtime.sendMessage({ type: 'TEST_API_KEY', payload: apiKey });
      setKeyStatus(ok ? 'ok' : 'fail');
      if (ok) {
        const ts = new Date().toLocaleString();
        setLastTested(ts);
        await chrome.storage.local.set({ lastKeyTest: ts });
      }
    } catch {
      setKeyStatus('fail');
    }
  }

  async function savePrefs(updated: UserPreferences) {
    setPrefs(updated);
    applyTheme(updated.theme);
    await chrome.storage.local.set({ preferences: updated });
    await chrome.storage.sync.set({ preferences: updated });
    setSaved(true);
    setTimeout(() => setSaved(false), 1500);
  }

  async function resetHistory() {
    const { sessionKeys } = await chrome.storage.local.get(['sessionKeys']);
    if (sessionKeys) {
      await chrome.storage.local.remove(sessionKeys as string[]);
    }
    await chrome.storage.local.remove(['sessionKeys']);
    setResetConfirm(false);
  }

  return (
    <div className="min-h-screen bg-[#FAFAF9] dark:bg-[#0F0F0F] text-zinc-900 dark:text-zinc-100 px-6 py-8">
      <div className="max-w-lg mx-auto">
        <div className="flex items-center gap-2 mb-8">
          <span className="text-amber-500 text-xl font-bold">◆</span>
          <span className="text-lg font-semibold">LeetCoach Settings</span>
          {saved && <span className="ml-auto text-xs text-green-500">Saved</span>}
        </div>

        {/* API Key */}
        <section className="mb-8">
          <h2 className="text-sm font-semibold mb-3 text-zinc-700 dark:text-zinc-300 uppercase tracking-wide">API Key</h2>
          <input
            type="password"
            value={apiKey}
            onChange={(e) => { setApiKey(e.target.value); setKeyStatus('idle'); }}
            placeholder="sk-ant-…"
            className="w-full rounded-lg border border-zinc-200 dark:border-zinc-700 bg-white dark:bg-zinc-900 px-3 py-2.5 text-sm focus:outline-none focus:ring-1 focus:ring-amber-500 mb-2"
          />
          <div className="flex items-center gap-3">
            <button
              onClick={testKey}
              disabled={!apiKey || keyStatus === 'testing'}
              className="rounded-lg bg-amber-500 px-4 py-2 text-sm font-medium text-white hover:bg-amber-600 disabled:opacity-50 transition-colors"
            >
              {keyStatus === 'testing' ? 'Testing…' : 'Test connection'}
            </button>
            {keyStatus === 'ok' && <span className="text-sm text-green-500">Connected ✓</span>}
            {keyStatus === 'fail' && <span className="text-sm text-red-500">Failed ✗</span>}
            {lastTested && keyStatus === 'idle' && (
              <span className="text-xs text-zinc-400">Last tested: {lastTested}</span>
            )}
          </div>
        </section>

        {/* Model */}
        <section className="mb-8">
          <h2 className="text-sm font-semibold mb-3 text-zinc-700 dark:text-zinc-300 uppercase tracking-wide">Model</h2>
          <div className="flex flex-col gap-2">
            {MODELS.map((m) => (
              <label
                key={m.id}
                className={`flex items-center justify-between rounded-[12px] border p-3 cursor-pointer transition-all ${
                  prefs.model === m.id
                    ? 'border-amber-500 bg-amber-50 dark:bg-amber-950'
                    : 'border-zinc-200 dark:border-zinc-800'
                }`}
              >
                <div className="flex items-center gap-2">
                  <input
                    type="radio"
                    name="model"
                    value={m.id}
                    checked={prefs.model === m.id}
                    onChange={() => savePrefs({ ...prefs, model: m.id })}
                    className="accent-amber-500"
                  />
                  <span className="text-sm font-medium">{m.label}</span>
                </div>
                <span className="text-xs text-zinc-400">{m.cost}</span>
              </label>
            ))}
          </div>
        </section>

        {/* Coach Style */}
        <section className="mb-8">
          <h2 className="text-sm font-semibold mb-3 text-zinc-700 dark:text-zinc-300 uppercase tracking-wide">Coach Style</h2>
          <div className="flex flex-col gap-2">
            {COACH_STYLES.map((s) => (
              <label
                key={s.id}
                className={`flex items-center gap-3 rounded-[12px] border p-3 cursor-pointer transition-all ${
                  prefs.coachStyle === s.id
                    ? 'border-amber-500 bg-amber-50 dark:bg-amber-950'
                    : 'border-zinc-200 dark:border-zinc-800'
                }`}
              >
                <input
                  type="radio"
                  name="coachStyle"
                  value={s.id}
                  checked={prefs.coachStyle === s.id}
                  onChange={() => savePrefs({ ...prefs, coachStyle: s.id })}
                  className="accent-amber-500"
                />
                <div>
                  <p className="text-sm font-medium">{s.label}</p>
                  <p className="text-xs text-zinc-400">{s.desc}</p>
                </div>
              </label>
            ))}
          </div>
        </section>

        {/* Theme */}
        <section className="mb-8">
          <h2 className="text-sm font-semibold mb-3 text-zinc-700 dark:text-zinc-300 uppercase tracking-wide">Theme</h2>
          <div className="flex gap-2">
            {(['auto', 'light', 'dark'] as Theme[]).map((t) => (
              <button
                key={t}
                onClick={() => savePrefs({ ...prefs, theme: t })}
                className={`flex-1 rounded-lg border py-2 text-sm font-medium capitalize transition-all ${
                  prefs.theme === t
                    ? 'border-amber-500 bg-amber-50 dark:bg-amber-950 text-amber-600'
                    : 'border-zinc-200 dark:border-zinc-700 text-zinc-500 hover:border-zinc-300'
                }`}
              >
                {t}
              </button>
            ))}
          </div>
        </section>

        {/* Reset */}
        <section className="mb-8">
          <h2 className="text-sm font-semibold mb-3 text-zinc-700 dark:text-zinc-300 uppercase tracking-wide">Data</h2>
          {!resetConfirm ? (
            <button
              onClick={() => setResetConfirm(true)}
              className="rounded-lg border border-red-200 dark:border-red-900 px-4 py-2 text-sm font-medium text-red-500 hover:bg-red-50 dark:hover:bg-red-950 transition-colors"
            >
              Reset hint history
            </button>
          ) : (
            <div className="flex gap-2">
              <button
                onClick={resetHistory}
                className="rounded-lg bg-red-500 px-4 py-2 text-sm font-medium text-white hover:bg-red-600 transition-colors"
              >
                Confirm reset
              </button>
              <button
                onClick={() => setResetConfirm(false)}
                className="rounded-lg border border-zinc-200 dark:border-zinc-700 px-4 py-2 text-sm font-medium text-zinc-500 hover:bg-zinc-50 dark:hover:bg-zinc-800 transition-colors"
              >
                Cancel
              </button>
            </div>
          )}
        </section>

        {/* About */}
        <section>
          <h2 className="text-sm font-semibold mb-3 text-zinc-700 dark:text-zinc-300 uppercase tracking-wide">About</h2>
          <p className="text-sm text-zinc-500 dark:text-zinc-400 mb-1">Version 1.0.0</p>
          <p className="text-xs text-zinc-400 leading-relaxed">
            Zero data leaves your device except direct calls to Anthropic's API.
            Your API key is stored in chrome.storage.local only.
          </p>
        </section>
      </div>
    </div>
  );
}
